// Strongly-typed hub
public interface IOrderClient
{
    Task OrderStatusUpdated(OrderStatusDto status);
    Task OrderCreated(OrderDto order);
}

public class OrderHub(IOrderService orderSvc) : Hub<IOrderClient>
{
    public async Task SubscribeToOrder(int orderId)
    {
        // Thêm connection vào group theo orderId
        await Groups.AddToGroupAsync(Context.ConnectionId, $"order:{orderId}");
    }

    public async Task<OrderDto> GetOrderStatus(int orderId)
    {
        return await orderSvc.GetAsync(orderId, Context.GetHttpContext()!.RequestAborted);
    }

    public override async Task OnDisconnectedAsync(Exception? ex)
    {
        _logger.LogInformation("Client {ConnectionId} disconnected: {Reason}",
            Context.ConnectionId, ex?.Message ?? "normal");
        await base.OnDisconnectedAsync(ex);
    }
}

// Server push từ background service
public class OrderEventHandler(IHubContext<OrderHub, IOrderClient> hubCtx)
{
    public async Task HandleStatusChanged(int orderId, string status, CancellationToken ct)
    {
        // Push tới tất cả subscribers của order này
        await hubCtx.Clients.Group($"order:{orderId}")
            .OrderStatusUpdated(new OrderStatusDto(orderId, status));
    }
}

